<?php include __DIR__.'/includes/header.php';$rows=db()->query("SELECT * FROM businesses WHERE status='Published' ORDER BY featured DESC,id DESC")->fetchAll();?><section class="section"><h1>Directory</h1><div class="grid"><?php if(!$rows): ?><div class="card"><h3>Directory launching soon</h3></div><?php endif; ?><?php foreach($rows as $r): ?><div class="card"><span class="badge"><?=h($r['category'])?></span><h3><?=h($r['name'])?></h3><p><?=h($r['description'])?></p></div><?php endforeach; ?></div></section><?php include __DIR__.'/includes/footer.php'; ?>